#include<iostream>
using std::cout;
class node
{
  public:   
   int n;
   class node *next;
};
class sll
{
   node *head;
public:
    sll();
   sll(int val);
   void append(int num);
   void insert(int num,int pos);
   void iter();
   node *getLastNode();
   ~sll();
};
node *createNode(int n)
{
   node * temp = new node;
   temp->n = n;
   temp->next = NULL;
   return temp;
}
sll::sll()
{
   head = NULL;
}
sll::sll(int val)
{
   node *nd = createNode(val);
   head = nd;
}
node* sll::getLastNode()
{
   node*temp = head;
   while(temp && temp->next!=NULL)
      temp = temp->next;
   return temp;
}
void sll::append(int num)
{
   node *nd = createNode(num);
   node* lastnode = getLastNode();
   if(lastnode!=NULL)
   {
      lastnode->next = nd;
   }
   else
   {
      head = nd;
   }
}
void sll::insert(int num,int pos)
{
   node *nd = createNode(num);
   //go to node pos-1
   node *temp = head;
   node * prevnd;
   for (int i=1;temp&&i<=pos;i++,temp=temp->next )
        prevnd = temp;   
   if(temp==NULL)
   {
      delete nd;
      append(num);
   }
   nd->next = prevnd->next;
   prevnd->next = nd;
}       
void sll::iter()
{
   node *temp = head;
   while(temp->next)
   {
      cout<<temp->n<<"=>";
      temp = temp->next;
   }
   if(temp)
      cout<<temp->n;
}
sll::~sll()
{
   //delete all the nodes
   node *temp = head;
   while(temp)
   {
      node *nextnode = temp->next;
        cout<<"Deleting the node"<<temp->n<<"\n";
      delete temp;
      temp = nextnode;
   }
   head = NULL;
}   
