{
   sll obj;
   for(int i=1;i<10;i++)
   {
      obj.append(i*i);
   }
    obj.insert(2000,3);
   obj.iter();
}

#include<iostream>
using namespace std;
int binarySearch(int *arr,int start,int end,int searchvalue)
{
	if(start>end)
	{
		return -1;
	}
	int mid = (start+end)/2;
	if(arr[mid]==searchvalue)
	    {
			return mid;
		}
	if(arr[mid]>searchvalue)
	{
	    return binarySearch(arr,start,mid-1,searchvalue);
	}
	else 
	{
		return binarySearch(arr,mid+1,end,searchvalue);
	}

}

int main()
{
   int arr[10];
     cout<<"Enter sorted array elements";
  for(int i=0;i<10;i++)
  {
      cout<<"arr["<<i<<"]=";
      cin>>arr[i];
  }
  int searchvalue;
  cout<<"Search value=";
  cin>>searchvalue;
  int index = binarySearch(arr,0,9,searchvalue);
  if(index==-1)
        cout<<"Search value is not found in array";
  else
        cout<<index<<" element is the Searchvalue";
  return 0;
}

