int sum_of_numbers(int a,int b)
{
    if(b>a)
    {
        int temp = a;
        a = b;
        b = temp;
    }
    int sum=0;
    for(int i=b;i<=a;i++)
    {
        sum+=i;
    }
    return sum;
}
