int Date::getYear()
{
    return yy;
}
 Date Date::operator +(int n)
{
    Date temp = *this;
    static int month_days[] = {31,28,31,30,31,30,31,31,30,31,30,31};
    temp.yy+=n/365;
    n = n%365;

    int incr_dd = temp.dd+n;

     int mn_days = month_days[temp.mm-1];
     if(temp.mm==2&&leapYear())
        {
            mn_days=29;
        }
    while(incr_dd>mn_days)
    {

           incr_dd -= mn_days;
            temp.mm++;

            if(temp.mm>12)
            {
                temp.mm-=12;
                temp.yy++;
            }
            mn_days = month_days[temp.mm-1];
        if(temp.mm==2&&leapYear())
        {
            mn_days=29;
        }
    }

    temp.dd = incr_dd;   
    return temp;
}
bool Date::leapYear()
{
    int rem = yy%4;
    int rem2  = yy%100;
    int rem3 = yy%400;
    if(rem3==0 )
    {
        return true;
    }
    if(rem2==0)
        return false;
    if(rem==0)
        return true;    
    return false;
}

