    for(int i=0;i<nr*nc;i++)
    {
        elements[i]=0;
    }
}

matrix::~matrix()
{
}
matrix::matrix(int nr,int nc)
{
    this->nr = nr;
    this->nc = nc;
    this->elements = new int[nr*nc];
    for(int i=0;i<nr*nc;i++)
    {
        elements[i]=0;
    }
}

int& matrix::operator()(int row,int col)
{
   int index = row*nc;
   index+=col;
   return elements[index];
}
