#include<iostream>
using std::cout;

template <class T>
struct node
{
    T num;
    struct node<T> *next;
};

template <class T>
class List
{
    node<T>  *first;
public:
    List();
    ~List();
    void append(T data);
    void insert(int pos,T data);
    void print();
    void delete_node(T data);
    node<T>* find_node(T data);   
    node<T>* create_node(T data);
    node<T>* find_last_node();
    node<T>* find_ith_node(int i);
    node<T>* find_previous_node(node<T> *nn);

};

template <class T>
List<T>::List()
{
    first = 0;/* initialize first node*/
}

template <class T>
List<T>::~List()
{
    while(first)
    {
        node <T>*temp = first;
        first = first->next;
        delete temp;
    }
}
template <class T>
node<T> * List<T>::create_node(T data)
{
    node<T> * newnode = new node<T>;
    newnode->num = data;
    newnode->next = 0;
    return newnode;
}
template <class T>
node<T> *List<T>::find_last_node()
{
    node<T> *temp = first;
    while(temp && temp->next)
        temp = temp->next;
    return temp;    
}
template <class T>
void List<T>::append(T data)
{
   node<T> *newnode = create_node(data);

   node<T> *last_node = find_last_node();
   if(!last_node)
   {
       first = newnode;
   }
   else{
       last_node->next = newnode;
   }
}
template <class T>
node<T> * List<T>::find_previous_node(node<T> * nn)
{
    node<T> * temp = first;
    while(temp && temp->next!=nn)
        temp = temp->next;
    return temp;    
}
template <class T>
node<T> * List<T>::find_ith_node(int pos)
{
    node<T> *temp = first;
    int i = 0;
    while(temp&&i!=pos)
    {
        temp = temp->next;
        i++;
    }

    return temp;    
}
template <class T>
void List<T>::insert(int pos,T data)
{
    node<T> * newnode = create_node(data);

    node<T> * ithnode = find_ith_node(pos);
    if(ithnode)
    {
        node<T> *prevnode = find_previous_node(ithnode);
        if(prevnode)
        {
            node<T> * nextnode = prevnode->next;
            prevnode->next = newnode;
            newnode->next = nextnode;            
        }
        else
        {
            /*i must be 0*/
            newnode->next = first;
            first= newnode;
        }
    }
    else/*no ith node. append*/
    {
        node<T> * last_node = find_last_node();
        if(last_node)
            last_node->next = newnode;
        else
            first  = newnode;
    }   

}
template <class T>
void List<T>::print()
{
    node<T> * temp = first;
    while(temp)
    {

        cout<<temp->num;
        if(temp->next)
            cout<<"==>";
        temp = temp->next;    
    }
    cout<<std::endl;
}

template <class T>
node<T> * List<T>::find_node(T data)
{
    node<T> * temp = first;
    while(temp && temp->num!=data)
        temp = temp->next;
    return temp;    
}
template <class T>
void List<T>::delete_node(T data)
{
    node<T> * temp = find_node(data);
    if(!temp)
    {
        cout<<"Value not found";
        return;
    }
    else
    {
        node<T> *prevnode = find_previous_node(temp);
        if(!prevnode)
        {
            /*we are deleting the first node*/
            first = first->next;
            delete temp;
        }
        else{
            prevnode->next = temp->next;
            /*link previous node to next node*/
            delete temp;
        }
    }
}

