bool collinear(point*pobj,int len)
{
    float prevSlope = pobj[0].gety()/pobj[0].getx();
    for(int i=1;i<len;i++)
     {
         float slope = pobj[i].gety()/pobj[i].getx();         
         if(prevSlope!=slope)
                   return false;
         prevSlope= slope;          
     }
     return true;
} 

bool readFile(char *filename,point pobj[])
{
    ifstream infile(filename);
    if(!infile)
    {
        cout<<"File open error";
        return false;
    }
    int i=0;
    while(infile)
    {
        float m1,m2;

        infile.ignore(100,'(');
        infile>>m1;
        infile.ignore(100,',');
        infile>>m2;
        infile.ignore(100,')');
        infile.ignore(100,',');
        pobj[i].setx(m1);
        pobj[i].sety(m2);
        i++;        
    }
    infile.close();

}
int main()
{   
    point pobj[5];
    readFile("./a.txt",pobj);

    for(int i=0;i<5;i++)
    {

        cout<<"("<<pobj[i].getx()<<","<<pobj[i].gety()<<")\n";
    }
    if(collinear(pobj,5)){
        cout<<"The points are collinear";
    }else{
        cout<<"The points are not collinear";
    }  
     return 0;
}

