void minmax(int a,int b,int c, int *minptr, int *maxptr)
{
   if(a>b && a>c)
     *maxptr = a;
   else if(b>a&& b>c)
     *maxptr = b;
   else
     *maxptr = c;

  if(a<b && a<c)
     *minptr = a;
   else if(b<a&& b<c)
     *minptr = b;
   else
     *minptr = c;
}
int main()
{
   int x,y,z;
   cout<<"Enter 3 numbers:";
   cin>>x>>y>>z;
   int max,min;
   minmax(x,y,z,&min,&max);
   cout<<"Minumum is "<<min<<" and maximum is "<<max;
   return 0;
}

bool isPrime(int n)
{
   if (n==1 || n==2)
     return true;
   if(n%2==0)
     return false;
   for(int i=3;i<n/2; i+=2)
      if(n%i==0)
        return false;
   return true;
}

